'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { User, Clock, Heart, LogOut, Edit2, Save } from 'lucide-react';

export default function ProfilePage() {
  const { user, logout, login } = useAuth();
  const [history, setHistory] = useState<any[]>([]);
  const [favorites, setFavorites] = useState<any[]>([]);
  const [isEditingName, setIsEditingName] = useState(false);
  const [newName, setNewName] = useState(user?.name || '');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (user) {
      fetch('http://localhost:5000/api/user/history', { credentials: 'include' })
        .then(res => res.json())
        .then(setHistory);
      fetch('http://localhost:5000/api/user/favorites', { credentials: 'include' })
        .then(res => res.json())
        .then(setFavorites);
    }
  }, [user]);

  const handleUpdateName = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('http://localhost:5000/api/user/profile', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newName }),
        credentials: 'include'
      });
      const updatedUser = await res.json();
      login(updatedUser);
      setIsEditingName(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const removeFavorite = async (id: string) => {
    try {
      await fetch(`http://localhost:5000/api/user/favorites/${id}`, { method: 'DELETE', credentials: 'include' });
      setFavorites(favorites.filter(f => f.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  if (!user) return <div className="p-8 text-center text-gray-400">Please log in to view your profile.</div>;

  return (
    <div className="container" style={{ paddingTop: '4rem', maxWidth: '1100px' }}>
      <div className="flex flex-col lg:flex-row gap-10 items-start">
        
        {/* Left Column: User Identity */}
        <div className="w-full lg:w-1/3 lg:sticky lg:top-24">
          <div className="bg-white/[0.03] border border-white/5 rounded-[32px] p-8 space-y-8">
            <div className="flex flex-col items-center text-center">
              <div className="w-24 h-24 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-indigo-500/20 rotate-3 hover:rotate-0 transition-transform duration-500">
                <User size={48} className="text-white" />
              </div>
              
              <div className="mt-6 w-full">
                {isEditingName ? (
                  <div className="flex flex-col gap-2">
                    <input 
                      value={newName} 
                      onChange={e => setNewName(e.target.value)}
                      className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-2 text-center text-white outline-none focus:ring-2 focus:ring-indigo-500"
                      placeholder="Your Name"
                    />
                    <button onClick={handleUpdateName} disabled={isLoading} className="w-full py-2 bg-indigo-600 text-white rounded-xl text-sm font-bold flex items-center justify-center gap-2">
                      <Save size={16} /> Save Changes
                    </button>
                  </div>
                ) : (
                  <div className="group relative">
                    <h1 className="text-2xl font-bold text-white group-hover:text-indigo-300 transition-colors">{user.name || 'Anonymous'}</h1>
                    <button onClick={() => setIsEditingName(true)} className="absolute -right-2 -top-1 p-1 bg-white/5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                      <Edit2 size={12} />
                    </button>
                  </div>
                )}
                <p className="text-gray-500 text-sm mt-1">{user.email}</p>
              </div>
            </div>

            <div className="space-y-4 pt-6 border-t border-white/5">
              <div className="flex justify-between items-center px-2">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Account Type</span>
                <span className="text-xs bg-indigo-500/10 text-indigo-400 px-2 py-1 rounded-md font-bold">Standard</span>
              </div>
              <div className="flex justify-between items-center px-2">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Member Since</span>
                <span className="text-xs text-gray-300 font-medium">{new Date(user.createdAt || Date.now()).toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</span>
              </div>
            </div>

            <button 
              onClick={logout} 
              className="w-full py-4 bg-white/5 hover:bg-red-500/10 text-gray-400 hover:text-red-400 rounded-2xl transition-all duration-300 flex items-center justify-center gap-3 font-bold text-sm"
            >
              <LogOut size={18} /> Sign Out
            </button>
          </div>
        </div>

        {/* Right Column: Content Hub */}
        <div className="flex-1 space-y-10 w-full">
          
          {/* Favorites Section */}
          <section className="space-y-6">
            <div className="flex items-center justify-between px-2">
              <h3 className="text-xl font-bold flex items-center gap-3">
                <Heart className="text-pink-500" size={24} />
                Saved Favorites
              </h3>
              <span className="text-xs font-bold text-gray-500 bg-white/5 px-3 py-1 rounded-full">{favorites.length} Items</span>
            </div>
            
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {favorites.length === 0 ? (
                <div className="col-span-2 py-12 text-center bg-white/[0.02] border border-dashed border-white/10 rounded-3xl">
                  <Heart className="mx-auto text-gray-700 mb-4" size={32} />
                  <p className="text-gray-500">Your favorites will appear here.</p>
                </div>
              ) : (
                favorites.map(fav => (
                  <div key={fav.id} className="group relative bg-white/[0.03] hover:bg-white/[0.06] border border-white/5 rounded-2xl p-5 transition-all">
                    <div className="flex justify-between items-start">
                      <span className="text-[10px] font-bold text-indigo-400 uppercase tracking-tighter bg-indigo-500/10 px-2 py-0.5 rounded">{fav.type}</span>
                      <button onClick={() => removeFavorite(fav.id)} className="opacity-0 group-hover:opacity-100 text-red-500 hover:scale-110 transition-all">
                        <Trash2 size={16} />
                      </button>
                    </div>
                    <h4 className="mt-3 font-bold text-white text-lg">{fav.title}</h4>
                  </div>
                ))
              )}
            </div>
          </section>

          {/* History Section */}
          <section className="space-y-6">
            <h3 className="text-xl font-bold flex items-center gap-3 px-2">
              <Clock className="text-indigo-400" size={24} />
              Recent Discoveries
            </h3>
            
            <div className="space-y-3">
              {history.length === 0 ? (
                <p className="text-gray-600 text-center py-8">No history found.</p>
              ) : (
                history.map(item => (
                  <div key={item.id} className="flex items-center gap-4 bg-white/[0.02] hover:bg-white/[0.04] p-4 rounded-2xl border border-white/5 transition-colors">
                    <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-indigo-400">
                      <Clock size={18} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs text-gray-500 font-medium truncate italic mb-0.5">"{item.query}"</p>
                      <h4 className="font-bold text-gray-200 truncate">{item.mainMatchTitle}</h4>
                    </div>
                    <span className="text-[10px] font-bold text-gray-600 uppercase tabular-nums">
                      {new Date(item.createdAt).toLocaleDateString()}
                    </span>
                  </div>
                ))
              )}
            </div>
          </section>

        </div>
      </div>
    </div>
  );

}
